    39→	private async getCurrentColorStyle(
    40→		styleId: number,
    41→		colorId?: number,
    42→	): Promise<IStyleColorBase | null> {
    43→		if (colorId) {
    44→			const styleByColor = await this.styleColorsService.getStyleByStyleAndColorId({
    45→				styleId,
    46→				colorId,
    47→			});
    48→			if (styleByColor) {
    49→				return styleByColor;
    50→			}
    51→		}
    52→
    53→		const style = await this.styleColorsService.getStyleByStyleId({ styleId });
    54→		if (!style) {
    55→			this.logger.warn('No style found', { styleId });
    56→		}
    57→		return style;
    58→	}
