    60→	async getRelatedProducts(
    61→		productId: string,
    62→		query: RelatedProductsQueryDto,
    63→	): Promise<RelatedProductsResponseDto> {
    64→		if (!productId || productId.trim() === '') {
    65→			this.logger.error('Product ID is required to fetch related products');
    66→			throw new BadRequestException('Product ID is required');
    67→		}
    68→
    69→		const numericProductId = Number(productId);
    70→		if (!Number.isInteger(numericProductId) || numericProductId <= 0) {
    71→			this.logger.error(`Invalid Product ID format: ${productId}`);
    72→			throw new BadRequestException(
    73→				`Product ID must be a valid positive integer, received: ${productId}`,
    74→			);
    75→		}
    76→
    77→		this.logger.log('[getRelatedProducts] Fetching related products', {
    78→			productId,
    79→			colorId: query.colorId,
    80→			limit: query.limit,
    81→		});
    82→		const { limit, colorId } = query;
    83→
    84→		try {
    85→			const styleIds = await this.algoliaService.getRelatedProductIds({
    86→				productId: numericProductId,
    87→			});
    88→
    89→			if (styleIds.length === 0) {
    90→				throw new NotFoundException(
    91→					`No related products found for product ID: ${productId}`,
    92→				);
    93→			}
    94→
    95→			const currentStyleColor = await this.getCurrentColorStyle(
    96→				numericProductId,
    97→				colorId,
    98→			);
    99→
   100→			const relatedProducts = await this.productHydrationService.hydrateProducts({
   101→				styleIds,
   102→				currentStyleColor,
   103→			});
   104→
   105→			if (relatedProducts.length === 0) {
   106→				throw new NotFoundException(
   107→					`No related products found for product ID: ${productId}`,
   108→				);
   109→			}
   110→
   111→			return {
   112→				product_id: productId,
   113→				related_products: relatedProducts.slice(0, limit),
   114→				color_id: colorId ?? null,
   115→			};
   116→		} catch (error: unknown) {
   117→			const err = error instanceof Error ? error : new Error(String(error));
   118→			this.logger.error(
   119→				`Error fetching related products from Algolia for productId ${productId}, colorId ${colorId}: ${err.message}`,
   120→				err.stack,
   121→			);
   122→
   123→			await this.metricsService.incrementDailyCounter(dailyTrackingKeys.MMS_REQUESTS);
   124→
   125→			const alternativeStyleIds =
   126→				await this.styleAlternativesService.getAlternativeStyleIds({
   127→					styleId: numericProductId,
   128→				});
   129→
   130→			if (alternativeStyleIds.length === 0) {
   131→				this.logger.warn(`No DB alternatives found for product ID: ${productId}`);
   132→				return {
   133→					product_id: productId,
   134→					related_products: [],
   135→					mms_fallback: true,
   136→					color_id: colorId ?? null,
   137→				};
   138→			}
   139→
   140→			const currentStyleColor = await this.getCurrentColorStyle(
   141→				numericProductId,
   142→				colorId,
   143→			);
   144→
   145→			const alternatives = await this.productHydrationService.hydrateProducts({
   146→				styleIds: alternativeStyleIds,
   147→				currentStyleColor,
   148→				activeOnly: true,
   149→			});
   150→
   151→			return {
   152→				product_id: productId,
   153→				related_products: alternatives.slice(0, limit),
   154→				mms_fallback: true,
   155→				color_id: colorId ?? null,
   156→			};
   157→		}
   158→	}
   159→
   160→	async getBrandProducts(
   161→		query: BrandProductsQueryDto,
   162→	): Promise<BrandProductsResponseDto> {
   163→		const { brand, limit, colorId, styleId, sortBy } = query;
   164→		try {
   165→			const { products, mvRecords } =
   166→				await this.productHydrationService.getProductsByBrands({
   167→					brands: [brand],
   168→					limit: 1000,
   169→				});
   170→
   171→			if (products.length === 0) {
   172→				throw new NotFoundException(`No products found for brand: ${brand}`);
   173→			}
   174→
   175→			let currentStyleColor: IStyleColorBase | null = null;
   176→			if (colorId && styleId) {
   177→				currentStyleColor = await this.styleColorsService.getStyleByStyleAndColorId({
   178→					styleId: Number(styleId),
   179→					colorId: Number(colorId),
   180→				});
   181→			}
   182→
   183→			const productsWithColor = currentStyleColor
   184→				? (() => {
   185→						const colorCache = new Map<
   186→							number,
   187→							ReturnType<
   188→								typeof this.productHydrationService.convertMvColorsToProductColors
   189→							>
   190→						>();
   191→						return products.map((product) => {
   192→							const mv = mvRecords.get(product.style_id);
   193→							let colors = colorCache.get(product.style_id);
   194→							if (!colors) {
   195→								colors = this.productHydrationService.convertMvColorsToProductColors(
   196→									mv?.colors ?? null,
   197→								);
   198→								colorCache.set(product.style_id, colors);
   199→							}
   200→							if (colors.length > 0 && currentStyleColor) {
   201→								const closestColorId = findClosestColorId(currentStyleColor, colors);
   202→								const closestColor = colors.find((c) => c.id === closestColorId);
   203→								if (closestColor) {
   204→									return {
   205→										...product,
   206→										color: closestColorId,
   207→										image_src: closestColor.image_url ?? product.image_src,
   208→									};
   209→								}
   210→							}
   211→							return product;
   212→						});
   213→					})()
   214→				: products;
   215→
   216→			let finalProducts = productsWithColor;
   217→
   218→			if (sortBy) {
   219→				let currentStyleCategoryId: number | null = null;
   220→				if (sortBy === 'category' && styleId) {
   221→					const currentStyle = await this.stylesService.getStyleById({
   222→						styleId: Number(styleId),
   223→					});
   224→					currentStyleCategoryId = currentStyle?.primary_category_id ?? null;
   225→				}
   226→				finalProducts = sortStyles({
   227→					products: productsWithColor,
   228→					sortBy,
   229→					currentStyleCategoryId,
   230→				});
   231→			}
   232→
   233→			return {
   234→				product_id: styleId?.toString() ?? '',
   235→				brand_products: finalProducts.slice(0, limit),
   236→				color_id: colorId ?? null,
   237→				brand,
   238→				sort_by: sortBy ?? null,
   239→			};
   240→		} catch (error: unknown) {
   241→			const err = error instanceof Error ? error : new Error(String(error));
   242→			this.logger.error(
   243→				`Failed to get products for brand ${query.brand}, styleId ${query.styleId}: ${err.message}`,
   244→				err.stack,
   245→			);
   246→
   247→			throw err;
   248→		}
   249→	}
   250→}
