     8→const logger = new Logger('findClosestColorId');
     9→
    10→// eslint-disable-next-line @typescript-eslint/require-await
    11→export async function findClosestColorId(
    12→	color: IStyleColorBase | null,
    13→	palette: IProductColor[],
    14→): Promise<number> {
    15→	if (!color || !palette.some((item) => item.rbgs?.length)) {
    16→		logger.warn(
    17→			'[findClosestColorId]: No color or palette provided, defaulting to color ID 0',
    18→		);
    19→		return 0;
    20→	}
    21→
    22→	const referenceColor = palette.find((item) => item.name === color.color_name);
    23→
    24→	if (referenceColor) {
    25→		logger.log(
    26→			`[findClosestColorId]: Exact color match found for "${color.color_name}", using color ID ${referenceColor.id}`,
    27→		);
    28→		return referenceColor.id;
    29→	}
    30→	const selectedColorRGB = color.color_rgb;
    31→
    32→	if (!selectedColorRGB || !palette.length) {
    33→		logger.warn(
    34→			'[findClosestColorId]: No selected color RGB or empty palette, defaulting to color ID 0',
    35→		);
    36→		return 0;
    37→	}
    38→
    39→	const colorsHash = getColorRGBToIdHash(palette);
    40→
    41→	const paletteColors = palette.reduce<RGBColor[]>((acc, color) => {
    42→		if (color.rbgs?.[0]) {
    43→			acc.push(color.rbgs[0]);
    44→		}
    45→		return acc;
    46→	}, []);
    47→
    48→	const closestColor = closest(convertStringToRGB(selectedColorRGB), paletteColors);
    49→
    50→	const closestColorId = colorsHash[convertRGBToString(closestColor)] ?? 0;
    51→
    52→	logger.log(
    53→		`[findClosestColorId]: Closest color to "${color.color_name}" (RGB: ${selectedColorRGB}) is color ID ${closestColorId}. colorsHash: ${JSON.stringify(colorsHash)}, paletteColors: ${JSON.stringify(paletteColors)}, closestColor: ${JSON.stringify(closestColor)}`,
    54→	);
    55→
    56→	return closestColorId;
    57→}
    58→
    59→function getColorRGBToIdHash(colors: IProductColor[]): Record<string, number> {
    60→	return colors.reduce<Record<string, number>>((acc, color) => {
    61→		if (color.rbgs?.[0]) {
    62→			acc[convertRGBToString(color.rbgs[0])] = color.id;
    63→		}
    64→		return acc;
    65→	}, {});
    66→}
    67→
    68→export function convertRGBToString(rgb: RGBColor): string {
    69→	return `R:${rgb.R},G:${rgb.G},B:${rgb.B}`;
    70→}
    71→
    72→export function convertStringToRGB(str: string): RGBColor {
    73→	const [R, G, B] = str.split(',');
    74→	return {
    75→		R: Number(R?.split(':')[1]),
    76→		G: Number(G?.split(':')[1]),
    77→		B: Number(B?.split(':')[1]),
    78→	};
    79→}
    80→

