     1→import { IRelatedProduct } from '@interfaces/related-product.interface';
     2→
     3→export function sortStyles({
     4→	products,
     5→	sortBy,
     6→	currentStyleCategoryId,
     7→}: {
     8→	products: IRelatedProduct[];
     9→	sortBy?: 'rating' | 'category' | undefined;
    10→	currentStyleCategoryId?: number | null;
    11→}): IRelatedProduct[] {
    12→	if (sortBy === 'category' && currentStyleCategoryId) {
    13→		return products.sort((a, b) => {
    14→			const aCategoryId = a.primary_category_id ?? 0;
    15→			const bCategoryId = b.primary_category_id ?? 0;
    16→
    17→			if (
    18→				aCategoryId !== currentStyleCategoryId &&
    19→				bCategoryId === currentStyleCategoryId
    20→			) {
    21→				return -1;
    22→			}
    23→
    24→			if (
    25→				bCategoryId !== currentStyleCategoryId &&
    26→				aCategoryId === currentStyleCategoryId
    27→			) {
    28→				return 1;
    29→			}
    30→
    31→			return 0;
    32→		});
    33→	}
    34→
    35→	if (sortBy === 'rating') {
    36→		return products.sort((a, b) => {
    37→			const aRating = Number(a.rating_score);
    38→			const bRating = Number(b.rating_score);
    39→
    40→			if (isNaN(aRating) && isNaN(bRating)) {
    41→				return 0;
    42→			}
    43→
    44→			if (isNaN(aRating)) {
    45→				return 1;
    46→			}
    47→
    48→			if (isNaN(bRating)) {
    49→				return -1;
    50→			}
    51→
    52→			return bRating - aRating;
    53→		});
    54→	}
    55→
    56→	return products;
    57→}
    58→

